import{_ as t,o as i,c as a,ag as n}from"./chunks/framework.CAXxHpAX.js";const h=JSON.parse('{"title":"Scoped Credential Nullifier — Spec Amendment","description":"","frontmatter":{},"headers":[],"relativePath":"specs/person-nullifier.md","filePath":"superpowers/specs/2026-04-18-person-nullifier-amendment.md","lastUpdated":1777988338000}'),s={name:"specs/person-nullifier.md"};function o(r,e,c,d,l,p){return i(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="scoped-credential-nullifier-—-spec-amendment" tabindex="-1">Scoped Credential Nullifier — Spec Amendment <a class="header-anchor" href="#scoped-credential-nullifier-—-spec-amendment" aria-label="Permalink to &quot;Scoped Credential Nullifier — Spec Amendment&quot;">​</a></h1><blockquote><p><strong>Renamed 2026-05-03</strong> — see <a href="./2026-05-03-zkqes-rename-design"><code>docs/superpowers/specs/2026-05-03-zkqes-rename-design.md</code></a> for the rename baseline. Historical references to QKB/QIE/Identity-Escrow in pre-2026-05-03 commits remain immutable in git history.</p></blockquote><blockquote><p>Amends §14.4 of <code>2026-04-17-qie-phase2-design.md</code> and §13.4 of <code>packages/contracts/CLAUDE.md</code>. Date: 2026-04-18. Clarified 2026-04-23. Status: authoritative.</p></blockquote><h2 id="_2026-04-23-clarification" tabindex="-1">2026-04-23 clarification <a class="header-anchor" href="#_2026-04-23-clarification" aria-label="Permalink to &quot;2026-04-23 clarification&quot;">​</a></h2><p>This primitive is <strong>not</strong> a pan-eIDAS natural-person deduplicator. It derives a context-bound nullifier from the identifier namespace exposed by the QES certificate&#39;s <code>subject.serialNumber</code> value. eIDAS trust lists establish that a QTSP/certificate chain is trusted; they do not require every Member State, QTSP, passport, or tax-number namespace held by the same natural person to collapse to one EU-wide identifier.</p><p>Applications may treat this as &quot;one registration per context per QES identifier namespace.&quot; If they need &quot;one natural person across multiple national identifiers,&quot; that must be supplied by a separate identity-escrow or deduplication layer above QKB.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>The prior Phase-2 nullifier construction was:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>secret    = Poseidon(subject_serial_limbs, issuer_cert_hash)</span></span>
<span class="line"><span>nullifier = Poseidon(secret, ctxHash)</span></span></code></pre></div><p>This binds the nullifier to a specific <strong>certificate</strong>, not to the identifier namespace represented by the QES subject. Every eIDAS QES is reissued every 1–3 years with a fresh certificate serial and subject public key. Under the prior construction, the same local QES identity produced a different nullifier after each renewal. The construction below fixes renewal/provider churn inside the exposed identifier namespace, but it still does not unify different national identifiers held by the same natural person.</p><h2 id="new-construction" tabindex="-1">New construction <a class="header-anchor" href="#new-construction" aria-label="Permalink to &quot;New construction&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>subjectSerialBytes  = subject.serialNumber attribute content (OID 2.5.4.5, PrintableString)</span></span>
<span class="line"><span>subjectSerialLen    = byte length of that content (1..32)</span></span>
<span class="line"><span>subjectSerialLimbs  = 4 × uint64 LE limbs packing the zero-padded-to-32 byte content</span></span>
<span class="line"><span>                      (limb[0] = bytes[0..8] LE, limb[1] = bytes[8..16] LE, …, limb[3] = bytes[24..32] LE)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>secret              = Poseidon(subjectSerialLimbs[0], subjectSerialLimbs[1],</span></span>
<span class="line"><span>                                subjectSerialLimbs[2], subjectSerialLimbs[3],</span></span>
<span class="line"><span>                                subjectSerialLen)                              — Poseidon-5</span></span>
<span class="line"><span>nullifier           = Poseidon(secret, ctxHash)                                 — Poseidon-2</span></span></code></pre></div><p>The limb packing is the one already produced by <code>X509SubjectSerial.circom</code> (committed as S0.2 on <code>feat/qie-circuits</code> at <code>f5dea56</code>): 32-byte capacity padded with zeros past <code>subjectSerialLen</code>, packed into 4 × uint64 little-endian limbs. MAX_SERIAL=32 comfortably covers every ETSI EN 319 412-1 semantics identifier observed in the wild (longest is ~24 chars for uncommon passport formats; typical <code>PNOXX-…</code> is 15–16). Hashing <code>subjectSerialLen</code> alongside the limbs prevents padding-collision between identifiers of different natural lengths (e.g. an 8-byte EDRPOU vs a 10-byte РНОКПП vs a 14-byte <code>PNODE-12345678</code>).</p><p>Design rationale over the earlier 16-byte / two-stage-Poseidon variant considered on 2026-04-18 morning:</p><ul><li><strong>Capacity</strong>: 16 was too tight for <code>TINUA-3627506575</code> (exactly 16 bytes) — zero headroom. 32 is adequate.</li><li><strong>Constraint cost</strong>: one Poseidon-5 (~400 constraints) beats Poseidon-16 + Poseidon-2 (~3500) by an order of magnitude. Relevant given the ECDSA presentation is at 7.63M / 8M budget.</li><li><strong>Reuse</strong>: <code>X509SubjectSerial.circom</code> already emits these limbs. Refactoring it into a byte-array emitter would be pure overhead.</li></ul><p>Cryptographic property is equivalent — the limb packing is a bijection over the padded bytes, so the inner hash over limbs is isomorphic to a hash over bytes modulo the field-element encoding.</p><h2 id="eidas-scope" tabindex="-1">eIDAS scope <a class="header-anchor" href="#eidas-scope" aria-label="Permalink to &quot;eIDAS scope&quot;">​</a></h2><p>ETSI EN 319 412-1 §5.1.3 — mandatory for every eIDAS QES — requires the subject <code>serialNumber</code> (OID 2.5.4.5) to carry a <strong>semantics identifier</strong> in the format:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;3-letter-type&gt;&lt;2-letter-country&gt;-&lt;national-unique-id&gt;</span></span></code></pre></div><p>where <code>&lt;3-letter-type&gt;</code> ∈ <code>{PAS, IDC, PNO, TAX, …}</code> per ETSI TS 119 412-1 Annex A. Examples:</p><table tabindex="0"><thead><tr><th>Value</th><th>Country</th><th>Scheme</th></tr></thead><tbody><tr><td><code>PNOUA-3456789012</code></td><td>UA</td><td>РНОКПП (natural person)</td></tr><tr><td><code>PNODE-12345678</code></td><td>DE</td><td>Steuer-ID</td></tr><tr><td><code>PNOFR-1850799123456</code></td><td>FR</td><td>NIR</td></tr><tr><td><code>PNOPL-89030303030</code></td><td>PL</td><td>PESEL</td></tr><tr><td><code>TINPL-1234567890</code></td><td>PL</td><td>Tax identification number</td></tr><tr><td><code>PASDE-C01X00T47</code></td><td>DE</td><td>Passport number</td></tr></tbody></table><p>The circuit hashes the raw PrintableString content bytes. It does NOT parse the semantics prefix. Consequently:</p><ul><li><strong>Pan-eIDAS coverage</strong>: any ETSI-compliant QES works without circuit changes. The primitive generalizes beyond Ukraine.</li><li><strong>Identifier-scheme-scoped</strong>: a person who holds both <code>PNODE-…</code> and <code>PASDE-…</code> certs from the same QTSP produces two distinct nullifiers — one per identifier scheme. This is intentional. Applications that need strict one-human-ever semantics need an escrow/deduplication layer; pinning a single identifier-type prefix only narrows the namespace and does not solve cross-country identity unification.</li><li><strong>Non-ETSI QES</strong>: certs without OID 2.5.4.5 fail witness generation with <code>witness.rnokppMissing</code>. The web SPA surfaces this as &quot;This flow currently requires an ETSI EN 319 412-1 compliant eIDAS QES.&quot;</li></ul><h2 id="on-chain-interface-compatibility" tabindex="-1">On-chain / interface compatibility <a class="header-anchor" href="#on-chain-interface-compatibility" aria-label="Permalink to &quot;On-chain / interface compatibility&quot;">​</a></h2><ul><li><code>QKBVerifier.Inputs.nullifier</code> (bytes32) — unchanged.</li><li>Public-signal index 13 — unchanged.</li><li><code>QKBRegistry.usedNullifiers</code> / <code>nullifierToPk</code> / <code>revokedNullifiers</code> — unchanged.</li><li><code>revokeNullifier(bytes32, bytes32)</code> — unchanged.</li></ul><p>Contracts require no rebuild. The change is circuit-internal (new witness inputs, new Poseidon sub-circuit) plus witness-builder (new offset + padded-bytes fields).</p><h2 id="backwards-compatibility" tabindex="-1">Backwards compatibility <a class="header-anchor" href="#backwards-compatibility" aria-label="Permalink to &quot;Backwards compatibility&quot;">​</a></h2><p><strong>None required.</strong> The Phase-1 Sepolia deployment at <code>0x7F36aF783538Ae8f981053F2b0E45421a1BF4815</code> shipped with 13-signal proofs (no nullifier) and remains addressable for existing Phase-1 bindings. The Phase-2 <code>QKBRegistryV2</code> at <code>0xcac30ff7B0566b6E991061cAA5C169c82A4319a4</code> (deployed 2026-04-18) has <code>usedNullifiers</code> empty — no prior production registrations to migrate. This amendment therefore lands transparently; the first registration against the rebuilt circuit writes the first entry.</p><h2 id="constraint-budget" tabindex="-1">Constraint budget <a class="header-anchor" href="#constraint-budget" aria-label="Permalink to &quot;Constraint budget&quot;">​</a></h2><p>ECDSA leaf+chain: currently 7.63 M constraints; hard cap 8 M. The new sub-circuit adds:</p><ul><li>16× byte-range check (<code>LessThan(9)</code>) — ~16 × 12 = 192 constraints</li><li>2× length bound check — ~40 constraints</li><li>16× padding-zero invariant — ~16 × 30 = 480 constraints</li><li>1× <code>Asn1ShortTLVCheck</code> (already present pattern) — ~2 × 12 = 24 constraints</li><li>16× Multiplexer slice from leafDER — ~16 × MAX_CERT = ~24 k constraints</li><li>2× <code>LessEqThan(16)</code> / <code>GreaterEqThan(16)</code> bounds — ~30 constraints</li><li>1× <code>Poseidon(16)</code> — ~3.5 k constraints</li><li>2× <code>Poseidon(2)</code> — ~600 constraints</li></ul><p>Total estimate: ~30 k constraints, well under the 80 k ceiling I allowed in the plan. If compile reports &gt; 7.95 M, fall back to a split proof (auxiliary nullifier circuit chained by <code>leafSpkiCommit</code> equality).</p><h2 id="witness-builder-contract" tabindex="-1">Witness-builder contract <a class="header-anchor" href="#witness-builder-contract" aria-label="Permalink to &quot;Witness-builder contract&quot;">​</a></h2><p>The witness builder MUST supply these new fields alongside existing inputs:</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Source</th></tr></thead><tbody><tr><td><code>rnokppOffset</code></td><td>uint (absolute offset in <code>leafDER</code>)</td><td>pkijs-parsed subject RDN walk, located via unique subarray match</td></tr><tr><td><code>rnokppLen</code></td><td>uint 1..16</td><td>length of the PrintableString content</td></tr><tr><td><code>rnokppPadded[16]</code></td><td>uint[16]</td><td>content bytes zero-padded to 16</td></tr></tbody></table><p>Public signal <code>nullifier</code> is derived off-circuit by <code>buildPersonSecret</code> + <code>buildNullifier</code> (see <code>packages/circuits/src/witness/nullifier.ts</code>) and compared constraint-side.</p><h2 id="test-surface" tabindex="-1">Test surface <a class="header-anchor" href="#test-surface" aria-label="Permalink to &quot;Test surface&quot;">​</a></h2><ul><li><code>test/nullifier.test.ts</code> — unit tests for the witness helpers (stable, differs-for-different-input, length-bound, length-hashing).</li><li><code>test/PersonNullifier.test.ts</code> — circuit unit test with KAT vectors.</li><li><code>test/QKBPresentationEcdsa.e2e.test.ts</code> — extended to assert the E2E-produced nullifier matches <code>fixtures/nullifier-kat.json#admin-ecdsa</code>.</li><li><code>fixtures/nullifier-kat.json</code> — contains <code>admin-ecdsa</code> and <code>synth-de</code> entries to prove pan-eIDAS coverage.</li></ul><h2 id="out-of-scope" tabindex="-1">Out of scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of scope&quot;">​</a></h2><ul><li><strong>RSA variant.</strong> Still deferred until we have non-Diia RSA QES test material. When it lands, the same <code>PersonNullifier</code> primitive wires in unchanged — only the leaf-cert DER path differs.</li><li><strong>Normalization across schemes.</strong> See eIDAS scope note above — explicitly out.</li><li><strong>Pan-eIDAS natural-person deduplication.</strong> Two QTSPs issuing certs with the same <code>subject.serialNumber</code> namespace/value produce the same nullifier. Two different national identifier namespaces for the same natural person do not. Cross-namespace deduplication is an identity-escrow problem, not a QES certificate-proof property.</li></ul>`,40)])])}const b=t(s,[["render",o]]);export{h as __pageData,b as default};
